// src/components/CouponForm/index.jsx

import React, { useState } from 'react'; // <-- Импортируем useState
import { useForm } from 'react-hook-form';
import { BASE_URL } from '../../utils/api';

// ***************************************************************
// ВРЕМЕННОЕ РЕШЕНИЕ: Компонент для отображения стилизованного уведомления
// Вам нужно будет заменить это на свой реальный модальный/уведомляющий компонент.
const ErrorNotification = ({ message, onClose }) => {
    if (!message) return null;

    return (
        <div 
            style={{
                position: 'fixed',
                top: '50%',
                left: '50%',
                transform: 'translate(-50%, -50%)',
                padding: '20px 30px',
                backgroundColor: '#fff',
                border: '1px solid #d88',
                borderRadius: '8px',
                zIndex: 1000,
                boxShadow: '0 4px 15px rgba(0,0,0,0.2)',
                maxWidth: '90%',
                textAlign: 'center',
                color: '#333'
            }}
        >
            <p style={{ color: '#C00', fontWeight: 'bold' }}>Ошибка валидации!</p>
            <p>{message}</p>
            <button 
                onClick={onClose} 
                style={{ marginTop: '10px', padding: '5px 15px', cursor: 'pointer' }}
            >
                Закрыть
            </button>
        </div>
    );
};
// ***************************************************************


const CouponForm = ({ className }) => { 
  const { 
    register, 
    handleSubmit, 
    formState: { errors, isValid }, // <-- Используем isValid
    reset 
  } = useForm({ mode: "onChange" }); // <-- Добавляем mode: "onChange" для лучшей реакции

  const [notification, setNotification] = useState(null); // <-- Состояние для уведомления

  const onSubmit = async (data) => {
    // 1. ПРОВЕРКА ОШИБОК ПЕРЕД ОТПРАВКОЙ
    if (!isValid) {
        // Собираем все сообщения об ошибках в одну строку
        const errorMessages = Object.values(errors)
            .map(err => err.message)
            .join(' | ');

        // Устанавливаем уведомление
        setNotification(errorMessages || "Пожалуйста, проверьте заполненные поля.");
        return; 
    }

    // 2. ОТПРАВКА (Продолжаем, только если валидация пройдена)
    setNotification(null); // Очищаем уведомление перед отправкой

    try {
      // ... (логика fetch остается прежней) ...
      const response = await fetch(`${BASE_URL}/sale/send`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data), // Можно использовать data напрямую
      });

      if (response.ok) {
        setNotification("Спасибо! Ваш купон на скидку отправлен.");
        reset(); 
      } else {
        setNotification('Ошибка при отправке заявки.');
      }
    } catch (error) {
      console.error('Ошибка сети:', error);
      setNotification('Ошибка соединения с сервером.');
    }
  };

  // ************* РЕНДЕРИНГ *************
  return (
    <>
        <form onSubmit={handleSubmit(onSubmit)} className={className}>

            {/* NAME FIELD */}
            <input
                type="text"
                placeholder="Name"
                {...register('name', { required: 'Введите имя' })}
            />
            {/* ❌ УДАЛЕНО ОТОБРАЖЕНИЕ ОШИБОК ПОД ПОЛЕМ */}

            {/* PHONE NUMBER FIELD */}
            <input
                type="tel"
                placeholder="Phone number"
                {...register('phone', { 
                    required: 'Введите номер телефона',
                    pattern: {
                        value: /^\+?[0-9\s-()]{7,20}$/,
                        message: 'Некорректный формат телефона'
                    }
                })}
            />
            {/* ❌ УДАЛЕНО ОТОБРАЖЕНИЕ ОШИБОК ПОД ПОЛЕМ */}

            {/* EMAIL FIELD */}
            <input
                type="email"
                placeholder="Email"
                {...register('email', { 
                    required: 'Введите email',
                    pattern: {
                        value: /^[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}$/i, 
                        message: 'Некорректный формат email'
                    }
                })}
            />
            {/* ❌ УДАЛЕНО ОТОБРАЖЕНИЕ ОШИБОК ПОД ПОЛЕМ */}

            {/* Кнопка */}
            <button type="submit">
              Get a discount
            </button>
        </form>

        {/* 🚀 ОТОБРАЖЕНИЕ МОДАЛЬНОГО УВЕДОМЛЕНИЯ */}
        <ErrorNotification 
            message={notification} 
            onClose={() => setNotification(null)} 
        />
    </>
  );
};

export default CouponForm;
